sys_script_include.script:
// Name: AlationSettingsAjax
// Client callable: true
// Extends: global.AbstractAjaxProcessor
var AlationSettingsAjax = Class.create();
AlationSettingsAjax.prototype = Object.extendsObject(global.AbstractAjaxProcessor, {
  _checkAccess: function () {
    if (!gs.hasRole('admin') && !gs.hasRole('x_alati_dpm_serv_0.admin'))
      throw 'Not authorized';
  },

  get: function () {
    var utils  = new AlationUtils();
    var host   = gs.getProperty('x_alati_dpm_serv_0.alation_host') || '';
    var tenant = gs.getProperty('x_alati_dpm_serv_0.tenant_id') || '';
	var regName = gs.getProperty('x_alati_dpm_serv_0.oauth_registry_name') || 'Alation Integration OAuth';
    var intUser = gs.getProperty('x_alati_dpm_serv_0.integration_user_name') || 'alation_integration';
    var scope   = gs.getProperty('x_alati_dpm_serv_0.oauth_scope') || '';

    return JSON.stringify({
		ok: true,
		alationHost: host,
		tenantId: tenant,
		oauthRegistryName: regName,
		integrationUsername: intUser,
		oauthScope: scope
    });
  },

  // Save settings & register (POST). Only persist if registration succeeds.
  save: function () {
    this._checkAccess();

    var utils = new AlationUtils();
    var reg   = new AlationRegistration();

    var host   = (this.getParameter('sysparm_alation_host') || '').trim();
    var tenant = (this.getParameter('sysparm_tenant_id')   || '').trim();

    if (!utils.isValidAlationHost(host))
      return JSON.stringify({ ok:false, error:'Alation Host must look like xyz.alationcloud.com' });
    if (!tenant)
      return JSON.stringify({ ok:false, error:'Provide Alation Tenant ID' });

		// NEW inputs
	var oauthClientSecret = (this.getParameter('sysparm_oauth_client_secret') || '').trim();
	var integrationPass   = (this.getParameter('sysparm_integration_password') || '').trim();

	// Optional inputs (non-secret)
	var oauthRegistryName = (this.getParameter('sysparm_oauth_registry_name') || 
	'Alation Integration OAuth').trim();
	var integrationUser   = (this.getParameter('sysparm_integration_username') || 'alation_integration').trim();
	var oauthScope        = (this.getParameter('sysparm_oauth_scope') || '').trim();

	// Validate required secrets for password grant
	if (!oauthClientSecret)
		return JSON.stringify({ ok:false, error:'OAuth Client Secret is required (paste from OAuth registry)' });
	if (!integrationPass)
		return JSON.stringify({ ok:false, error:'Integration user password is required (for password grant)' });

	// Persist secrets (password2 props)
	gs.setProperty('x_alati_dpm_serv_0.oauth_client_secret', oauthClientSecret);
	gs.setProperty('x_alati_dpm_serv_0.integration_user_password', integrationPass);

	// Persist non-secret defaults
	gs.setProperty('x_alati_dpm_serv_0.oauth_registry_name', oauthRegistryName);
	gs.setProperty('x_alati_dpm_serv_0.integration_user_name', integrationUser);
	gs.setProperty('x_alati_dpm_serv_0.oauth_scope', oauthScope);

    // Call registration first (POST)
    var regRes = reg.registerWithGoService(host, tenant, 'POST', utils.getOrCreateApiKey());
    if (!regRes || regRes.ok !== true) {
      var msg = (regRes && (regRes.reason || regRes.body)) || 'Registration failed';
      // unwrap JSON error from Go if possible
      try { var b = JSON.parse(String(regRes.body || '{}')); msg = String(b.error || b.message || msg); } catch (ignore) {}
      return JSON.stringify({ ok:false, error: msg, status: regRes && regRes.status ? Number(regRes.status) : 0 });
    }

    // Persist only on success
    gs.setProperty('x_alati_dpm_serv_0.alation_host', utils.normalizeHost(host));
    gs.setProperty('x_alati_dpm_serv_0.tenant_id', tenant);

    return JSON.stringify({ ok:true, message:'Settings updated.' });
  },

  // ---------- NEW: Rotate API key & PUT register ----------
  rotate_token: function () {
    this._checkAccess();
    var utils = new AlationUtils();
    var reg   = new AlationRegistration();

    var host   = gs.getProperty('x_alati_dpm_serv_0.alation_host') || '';
    var tenant = gs.getProperty('x_alati_dpm_serv_0.tenant_id') || '';
    if (!utils.isValidAlationHost(host))
      return JSON.stringify({ ok:false, error:'Alation Host not configured' });
    if (!tenant)
      return JSON.stringify({ ok:false, error:'Alation Tenant ID not configured' });

    // Rotate local key
    var fresh = utils.rotateApiKey();

    // PUT to update registration (send fresh token)
    var regRes = reg.registerWithGoService(host, tenant, 'PUT', fresh);
    if (!regRes || regRes.ok !== true) {
      var msg = (regRes && (regRes.reason || regRes.body)) || 'Token rotate failed';
      try { var b = JSON.parse(String(regRes.body || '{}')); msg = String(b.error || b.message || msg); } catch (ignore) {}
      return JSON.stringify({ ok:false, error: msg, status: regRes && regRes.status ? Number(regRes.status) : 0 });
    }

    return JSON.stringify({ ok:true, message:'New token generated & registered.' });
  },

  type: 'AlationSettingsAjax'
});
